import UIKit
import Web3
import CryptoSwift

class ViewController: UIViewController {

    override func viewDidLoad() {
        super.viewDidLoad()
        
        // Example usage
        let privateKey = generatePrivateKey()
        print("Private Key: \(privateKey)")
        
        if let signedTransaction = signTransaction(privateKey, transaction: "0x1234567890") {
            print("Signed Transaction: \(signedTransaction.hexString!)")
        }
    }

    func generatePrivateKey() -> Data {
        return CryptoSwift.AES(key: Array(repeating: 0x00, count: 32)).encrypt(Array(repeating: 0xAA, count: 16))
    }

    func signTransaction(_ privateKey: Data, transaction: String) -> Data? {
        let keyPair = Web3.KeyPair(privateKey: privateKey)
        let hashToSign = keccak256(Data(hexString: transaction)!).bytes
        return keyPair.sign(hashToSign)?.signature
    }
}